echo "=========================================="
echo "      DKST 한글 입력기 설치 준비         "
echo "=========================================="
if [ "$RELEASE_CHANNEL" = "beta" ]; then
    echo "최신 베타 릴리즈 정보를 확인 중입니다..."
else
    echo "최신 정식 릴리즈 정보를 확인 중입니다..."
fi

RELEASE_JSON="$(curl -fsSL \
    -H "Accept: application/vnd.github+json" \
    -H "X-GitHub-Api-Version: 2022-11-28" \
    "$API_URL")"

RELEASE_INFO="$(printf '%s\n' "$RELEASE_JSON" | awk -v channel="$RELEASE_CHANNEL" '
function reset_release() {
    tag = ""
    prerelease = ""
    in_assets = 0
    asset_name = ""
}
function json_value(line, value) {
    value = line
    sub(/^[^:]*: *"/, "", value)
    sub(/",? *$/, "", value)
    return value
}
BEGIN {
    reset_release()
}
/"tag_name":/ {
    tag = json_value($0)
}
/"prerelease":/ {
    prerelease = $0
    sub(/^[^:]*: */, "", prerelease)
    sub(/,? *$/, "", prerelease)
}
/"assets": *\[/ {
    in_assets = 1
}
in_assets && /"name":/ {
    asset_name = json_value($0)
}
in_assets && /"browser_download_url":/ {
    asset_url = json_value($0)
    is_beta = (tolower(tag) ~ /beta/)
    is_dkst_zip = (asset_name ~ /^DKST-.*\.zip$/)
    if (channel == "stable" && tag != "" && asset_url != "" &&
        prerelease == "false" && !is_beta && is_dkst_zip) {
        print tag
        print asset_url
        print asset_name
        exit
    }
    if (channel == "beta" && tag != "" && asset_url != "" && is_beta && is_dkst_zip) {
        print tag
        print asset_url
        print asset_name
        exit
    }
    asset_name = ""
}
')"

TAG_NAME="$(printf '%s\n' "$RELEASE_INFO" | sed -n '1p')"
ASSET_ZIP_URL="$(printf '%s\n' "$RELEASE_INFO" | sed -n '2p')"
ASSET_NAME="$(printf '%s\n' "$RELEASE_INFO" | sed -n '3p')"

if [ -z "$TAG_NAME" ]; then
    if [ "$RELEASE_CHANNEL" = "beta" ]; then
        echo "오류: 설치 가능한 베타 릴리즈 태그를 확인하지 못했습니다."
    else
        echo "오류: 설치 가능한 정식 릴리즈 태그를 확인하지 못했습니다."
    fi
    exit 1
fi

if [ -z "$ASSET_ZIP_URL" ]; then
    echo "오류: ${TAG_NAME} 릴리즈에서 설치용 DKST zip asset을 찾지 못했습니다."
    echo "릴리즈 asset에 DKST-버전.zip 형식의 파일이 등록되어 있는지 확인해주세요."
    exit 1
fi

echo "대상 릴리즈: ${TAG_NAME}"
echo "설치 파일: ${ASSET_NAME}"
echo "DKST 설치용 zip 다운로드 중..."
curl -fL "$ASSET_ZIP_URL" -o "$ARCHIVE_PATH"

echo "압축 해제 중..."
mkdir -p "$EXTRACT_DIR"
ditto -x -k "$ARCHIVE_PATH" "$EXTRACT_DIR"

INSTALL_COMMAND="$(find "$EXTRACT_DIR" -type f -name "install.command" -print | head -n 1)"

if [ -z "$INSTALL_COMMAND" ]; then
    echo "오류: 압축 파일 안에서 install.command를 찾지 못했습니다."
    exit 1
fi

chmod +x "$INSTALL_COMMAND"

echo ""
echo "DKST 한글 입력기 설치 도우미를 실행합니다."
echo ""
"$INSTALL_COMMAND"
